mapper.select:
SELECT
    a.id,
    a.time_id timeId,
    a.travel_day `start`,
    a.travel_day `end`
FROM
    check_work_business_travel_time_slot a,
    check_work_business_travel b

    b.create_id = #{userId}
    AND b.id = a.parent_id
    AND a.state = #{childState}
    AND a.time_id = #{timeId}


            #{month}



        AND a.tenant_id = #{tenantId} AND b.tenant_id = #{tenantId}
